<template><el-card><template #header>{{title}}</template><PageToolbar><el-input v-model="q" placeholder="搜索"/><template #actions><el-button type="primary" @click="rows.unshift({name:'新建'+title,code:'NEW',status:'启用',desc:'模拟新增'})">新建</el-button></template></PageToolbar><DataTable :data="rows"><el-table-column prop="name" label="名称"/><el-table-column prop="code" label="编码"/><el-table-column prop="status" label="状态"/><el-table-column prop="desc" label="说明"/><el-table-column label="操作"><template #default="s"><el-button link>编辑</el-button><el-button link type="danger" @click="s.row.status='停用'">停用</el-button></template></el-table-column></DataTable></el-card></template>
<script setup lang="ts">import { computed, ref, watch } from 'vue'; import { useRoute } from 'vue-router'; import { titleByPath } from '@/router/menu'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; const route=useRoute(); const title=computed(()=>titleByPath(route.path).at(-1)); const q=ref(''); const rows=ref<any[]>([]); function reset(){rows.value=Array.from({length:5},(_,i)=>({name:`${title.value}${i+1}`,code:`SYS_${i+1}`,status:'启用',desc:'系统管理模拟数据'}))} watch(()=>route.path,reset,{immediate:true});</script>
